import{_ as t,o as e,c as r,ak as d}from"./chunks/framework.v1e5hYbe.js";const n="/MenuManager/assets/overview.B_KdE_Z2.png",m=JSON.parse('{"title":"Lyra Menu Manager","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),o={name:"guide/index.md"};function i(h,a,l,s,u,c){return e(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="lyra-menu-manager" tabindex="-1">Lyra Menu Manager <a class="header-anchor" href="#lyra-menu-manager" aria-label="Permalink to &quot;Lyra Menu Manager&quot;">​</a></h1><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>VRChatのエクスプレッションメニューおよび、Modular Avatarによって導入される拡張メニュー群を、VRChat内メニューと同様の円形UIで視覚的に整理・編集できるUnityエディター拡張ツールです。</p><p>Modular Avatarによる多数のギミック追加により複雑化・肥大化しがちなメニュー構造を、ドラッグ＆ドロップなどの簡単な操作で、非破壊に整理することが可能です。自分好みの見やすいカスタム階層の構築をサポートします。</p><p><img src="'+n+'" alt="全体UIスクリーンショット"></p><hr><h2 id="主な特徴" tabindex="-1">主な特徴 <a class="header-anchor" href="#主な特徴" aria-label="Permalink to &quot;主な特徴&quot;">​</a></h2><h3 id="ui" tabindex="-1">UI <a class="header-anchor" href="#ui" aria-label="Permalink to &quot;UI&quot;">​</a></h3><p>VRChatゲーム内と同じレイアウトのメニューUIをエディター上にそのまま再現しています<br> 完成イメージを直接見ながら、迷うことなく編集が可能です。</p><h3 id="ドラッグ-ドロップ操作" tabindex="-1">ドラッグ＆ドロップ操作 <a class="header-anchor" href="#ドラッグ-ドロップ操作" aria-label="Permalink to &quot;ドラッグ＆ドロップ操作&quot;">​</a></h3><p>アイテムを掴んでドラッグし、順番の入れ替えやサブメニューへの移動など、直感的に階層を組み替えることができます。</p><h3 id="modular-avatar-完全対応" tabindex="-1">Modular Avatar 完全対応 <a class="header-anchor" href="#modular-avatar-完全対応" aria-label="Permalink to &quot;Modular Avatar 完全対応&quot;">​</a></h3><p>標準のExpression Menuに加えて、アバター内に分散している <code>MA Menu Installer</code> を自動で集約・リストアップするため、ヒエラルキー内に散らばったメニュー設定を探し回る必要がありません。<br> また、参照を記憶するため、どのメニューアイテムがどのオブジェクトのMAから追加されているかをワンクリックで確認できます。</p><h3 id="インベントリシステム" tabindex="-1">インベントリシステム <a class="header-anchor" href="#インベントリシステム" aria-label="Permalink to &quot;インベントリシステム&quot;">​</a></h3><p>メニューに登録したくないアイテムや、一時的に整理しておきたいアイテムを、左パネルのインベントリに収納できるシステムを実装しています。 インベントリ内ではUnityのヒエラルキーのように一覧で確認ができ、ここにある場合はメニューに登録されません。</p><h3 id="ndmf経由の完全非破壊での適用" tabindex="-1">NDMF経由の完全非破壊での適用 <a class="header-anchor" href="#ndmf経由の完全非破壊での適用" aria-label="Permalink to &quot;NDMF経由の完全非破壊での適用&quot;">​</a></h3><p>変更したメニューのレイアウト情報は独自の専用コンポーネントに保存され、ビルド実行時にNDMFに介入し自動でメニューに適用されます。元のMAコンポーネントやアセットを書き換えず、コンポーネントの削除で元通りにすることが可能です。</p><hr><h2 id="動作確認環境" tabindex="-1">動作確認環境 <a class="header-anchor" href="#動作確認環境" aria-label="Permalink to &quot;動作確認環境&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>要件</th></tr></thead><tbody><tr><td>Unity</td><td>2022.3.22f1</td></tr><tr><td>VRChat SDK</td><td>3.10.1</td></tr><tr><td>Modular Avatar</td><td>1.16.2</td></tr><tr><td>NDMF</td><td>1.11.0</td></tr></tbody></table>',20)])])}const b=t(o,[["render",i]]);export{m as __pageData,b as default};
